  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→import type { NoteEntry } from '../../data/notes_data';
 10→import { MOCK_NOTE_ENTRIES } from '../../data/notes_data';
 11→import { useAlert } from '../../hooks/use_alert';
 12→import { useDbSearch } from '../../hooks/use_db_search';
 13→import { useHUD } from '../../hooks/use_hud';
 14→import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
