@use '../../styles/tokens';

.notes-editor {
  display: flex;
  flex-direction: column;
  flex: 1;
  padding: tokens.$space-3;
  gap: tokens.$space-3;
  overflow-y: auto;

  &__title-input {
    width: 100%;
    background: transparent;
    border: none;
    outline: none;
    font-family: tokens.$font-family;
    font-size: tokens.$font-lg;
    font-weight: tokens.$font-weight-medium;
    color: var(--color-text-primary);
    padding: tokens.$space-1 0;

    &::placeholder {
      color: var(--text-400);
    }
  }

  &__content-area {
    flex: 1;
    width: 100%;
    background: transparent;
    border: none;
    outline: none;
    font-family: tokens.$font-family-mono;
    font-size: tokens.$font-md;
    color: var(--color-text-primary);
    resize: none;
    line-height: 1.6;
    min-height: 200px;

    &::placeholder {
      color: var(--text-400);
    }
  }

  &__meta {
    display: flex;
    align-items: center;
    gap: tokens.$space-2;
    font-size: tokens.$font-xs;
    color: var(--text-400);
    padding-top: tokens.$space-1;
    border-top: 1px solid var(--border-100);
  }
}

